question.template:
import contextlib
import io
import json
import re

student_code = """{{ STUDENT_ANSWER | e('py') }}"""
rows = [["Check", "Expected", "Got", "Comment", "Mark", "iscorrect"]]
total_awarded = 0.0

expected_dataset = [
    {
        "id": "flower1",
        "sepal_length": 5.1,
        "sepal_width": 3.5,
        "petal_length": 1.4,
        "petal_width": 0.2,
        "species": "setosa",
    },
    {
        "id": "flower2",
        "sepal_length": 4.9,
        "sepal_width": 3.0,
        "petal_length": 1.4,
        "petal_width": 0.2,
        "species": "setosa",
    },
]


def compact(value):
    text = str(value)
    if len(text) > 220:
        return text[:217] + "..."
    return text


def cleaned_lines(text):
    return [line.rstrip() for line in text.splitlines() if line.strip()]


def add_result(label, expected, got, comment, awarded, mark, iscorrect):
    global total_awarded
    total_awarded += awarded
    rows.append([
        label,
        compact(expected),
        compact(got),
        comment,
        f"{awarded:.1f}/{mark:.1f}",
        iscorrect,
    ])


def require_callable(namespace, name):
    obj = namespace.get(name)
    if not callable(obj):
        raise NameError(f"Function '{name}' is missing or not callable.")
    return obj


def sanitize(code, fix_return=True, fix_main_status=True):
    if fix_return:
        code = re.sub(
            r"return\s*<\s*your_code\s*>\s*,\s*wrong\s*,\s*<\s*your_code\s*>\s*,\s*<\s*your_code\s*>",
            "return correct, wrong, total, y_pred_list",
            code,
        )
    if fix_main_status:
        code = re.sub(
            r"make_print_status\(\s*<\s*your_code\s*>\s*\)",
            'make_print_status("Print summary")',
            code,
        )
    return code


def load_namespace(fix_return=True, fix_main_status=True):
    code = sanitize(student_code, fix_return=fix_return, fix_main_status=fix_main_status)
    compiled = compile(code, "<student>", "exec")
    namespace = {"__name__": "student_submission"}
    with contextlib.redirect_stdout(io.StringIO()):
        exec(compiled, namespace)
    return namespace

DEFAULT_GRADE = 1.0

try:
    namespace = load_namespace()
    func = require_callable(namespace, "update_result_counts")
    correct_case = func(0, 0, 0, [], "setosa", "setosa")
    wrong_case = func(1, 0, 1, ["setosa"], "not_setosa", "setosa")
    success = correct_case == (1, 0, 1, ["setosa"]) and wrong_case == (1, 1, 2, ["setosa", "not_setosa"])
    add_result("Task 7", "update_result_counts returns updated counters, total, and prediction list", {"correct_case": correct_case, "wrong_case": wrong_case}, "The function should handle both correct and wrong predictions.", 1.0 if success else 0.0, 1.0, 1 if success else 0)
except Exception as exc:
    add_result("Task 7", "Metric update function works", f"{type(exc).__name__}: {exc}", "The code could not be imported for Task 7.", 0.0, 1.0, 0)

print(json.dumps({
    "fraction": total_awarded / DEFAULT_GRADE,
    "testresults": rows,
}))
